WOMT_aTexte['popup_faq_8_text']=new Array();
WOMT_aTexte['popup_faq_8_text'][0]='Auf der Seite, die Sie von Ihrem Wahl-O-Mat Ergebnis durch einen Klick auf "weiter" oder "Welche Argumente? So begründen die Parteien ihre Positionen!" erreichen, können Sie sich noch einmal durch alle Thesen des Wahl-O-Mat durchklicken. Neben Ihrem Votum sehen Sie auch die Antworten der Parteien bzw. Wählervereinigungen ("stimme zu" = Häkchen, "stimme nicht zu" = Kreuz, "neutral" = oranges Kästchen ohne Symbol und "These überspringen" = graues Kästchen ohne Symbol). Mit einem kurzen Klick auf den Namen der jeweiligen Partei zeigt Ihnen der Wahl-O-Mat die Begründung der Partei für ihr Antwortverhalten zu der entsprechenden These an.';
